import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { ExternalSystemEditComponent } from './external-system-edit/external-system-edit.component';
import { ExternalSystemNewComponent } from './external-system-new/external-system-new.component';
import { ExternalSystemComponent } from './external-system/external-system.component';
import { ProcessCodeMappingEditComponent } from './process-code-mapping-edit/process-code-mapping-edit.component';
import { ProcessCodeMappingNewComponent } from './process-code-mapping-new/process-code-mapping-new.component';
import { ProcessCodeMappingComponent } from './process-code-mapping/process-code-mapping.component';
import { TreasuryReferenceComponent } from './treasury-reference/treasury-reference.component';


const routes: Routes = [
  {
    path: 'extSys-summary',
    component: ExternalSystemComponent
  },
   {
    path: 'extSys-new',
    component: ExternalSystemNewComponent
  },
  {
    path: 'extSys-edit',
    component: ExternalSystemEditComponent
  },
   {
    path: 'processCodeMapping',
    component: ProcessCodeMappingComponent
  }, {
    path: 'processCodeMappingNew',
    component: ProcessCodeMappingNewComponent
  },
  {
    path: 'processCodeMappingEdit',
    component: ProcessCodeMappingEditComponent
  },
  {
    path: 'treasuryReference',
    component: TreasuryReferenceComponent
  },
  
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class FileUploadMaintenanceRoutingModule { }
